  ('social-worker-moex-02147', 'social-worker', 'social-worker-moex-106-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '什麼是社會工作研究的第一步？', '["廣泛閱讀文獻", "構思研究方法", "發想研究問題", "注意研究倫理"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "88073911b247", "answer_pdf_sha1": "449337010204", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02148', 'social-worker', 'social-worker-moex-106-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '執行研究是為了解概念，但我們仍得在研究前，針對概念給予基本描述與簡要定義。請問這個步驟是：', '["操作化", "概念化", "變項化", "通則化"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "88073911b247", "answer_pdf_sha1": "449337010204", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02149', 'social-worker', 'social-worker-moex-106-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '皮爾森相關係數（r）有幾個特色，下列敘述何者錯誤？', '["相關係數為零表示兩個變項間可能沒有關係", "相關係數為正值表示正相關", "相關係數介於-1與+1之間", "相關係數有單位"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "88073911b247", "answer_pdf_sha1": "449337010204", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
